noncompliant:
struct MyStruct {
  signed int flag:1;  // Noncompliant: only room for sign bit
  signed char status:1;  // Noncompliant: only room for sign bit
};

typedef struct {
  signed short ready:1;  // Noncompliant
} State;

compliant:
struct MyStruct {
  unsigned int flag:1;  // Compliant: can represent 0 or 1
  unsigned char status:1;  // Compliant
};

struct MyStruct {
  signed int flag:2;  // Compliant: has value bits
  signed int :1;  // Compliant: unnamed bit field
};
